<template>
	<view>
		<view class="title">
			{{ title }}
		</view>
		<view>
			<input :type="type" class="inputBox" :value="modelValue" @input="handleInput" :placeholder="placeholder" />
		</view>
	</view>
</template>

<script setup>
	const props = defineProps({
		type: {
			type: String,
			default: 'text'
		},
		title: String,
		placeholder: {
			type: String,
			default: "请输入内容"
		},
		// 👇 必须接收来自父组件的 v-model 值
		modelValue: {
			type: String,
			default: ''
		}
	})

	const emit = defineEmits(['update:modelValue'])

	// 处理输入事件
	const handleInput = (e) => {
		const value = e.detail?.value || e.target?.value || '' // 兼容 uni-app 和 web
		emit('update:modelValue', value)
	}
</script>

<style scoped>
	/* @import url('https://fonts.googleapis.com/css2?family=Noto+Serif+SC:wght@400;700&display=swap'); */

	.inputBox {
		background-color: rgba(15, 7, 0, 0.4);
		border-radius: 40rpx;
		width: 550rpx;
		height: 100rpx;
		font-size: 20px;
	}

	.inputBox {
		background-color: rgba(15, 7, 0, 0.4);
		border-radius: 50rpx;
		width: 90%;
		height: 100rpx;
		font-size: 20px;
		padding: 0 25px;
		color: #fff;
		border: none;
		outline: none;
		transition: all 0.3s ease;
		box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
	}

	.inputBox::placeholder {
		color: rgba(255, 255, 255, 0.6);
	}

	.inputBox:focus {
		background-color: rgba(15, 7, 0, 0.5);
		box-shadow:
			0 0 0 2px rgba(255, 255, 255, 0.3),
			0 0 15px rgba(255, 215, 100, 0.6);
	}

	.title {
		color: white;
		font-size: 24px;
		font-weight: 900;
		font-family: 'Noto Serif SC', serif;

	}
</style>